(1, 'Colección 2026', 'Camiseta local Alemania 26', 'Camiseta oficial de la Selección de Alemania para el Mundial 2026. Diseño blanco clásico con detalles en negro y el águila federal bordada. Versión Fan con tela transpirable y corte moderno.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/alemania_2026_version_fan_1.webp','img/alemania_2026_version_fan_2.webp','img/alemania_2026_version_fan_3.webp','img/alemania_2026_version_fan_4.webp','img/alemania_2026_version_fan_5.webp','img/alemania_2026_version_fan_6.webp','img/alemania_2026_version_fan_7.webp']),
(2, 'Colección 2026', 'Camiseta local Argentina 26', 'La camiseta más icónica del mundo en su versión 2026. Rayas celeste y blanco con detalles dorados en honor a los campeones del mundo. Versión Fan de alta calidad para los verdaderos hinchas de la Albiceleste.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/argnetina_2026_home_fan_1.webp','img/argnetina_2026_home_fan_2.webp','img/argnetina_2026_home_fan_3.webp']),
