(4, 'Temporada 25/26', 'Camiseta local Arsenal 25/26', 'Camiseta local del Arsenal para la temporada 2025-26. El rojo intenso de Emirates Stadium con detalles en blanco y el escudo de los Gunners. Versión Fan con tela ligera y transpirable.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/arsenal_25-26_home_fan_1.webp','img/arsenal_25-26_home_fan_2.webp','img/arsenal_25-26_home_fan_3.webp','img/arsenal_25-26_home_fan_4.webp','img/arsenal_25-26_home_fan_5.webp','img/arsenal_25-26_home_fan_6.webp','img/arsenal_25-26_home_fan_7.webp','img/arsenal_25-26_home_fan_8.webp','img/arsenal_25-26_home_fan_9.webp']),
(5, 'Temporada 25/26', 'Camiseta local Barcelona 25/26', 'La nueva camiseta local del FC Barcelona temporada 2025-26 con los legendarios colores blaugrana. Franjas clásicas rediseñadas con toque moderno y escudo bordado. Versión Fan premium para los culers del mundo.', 99000, 10.44, '{"S":0,"M":2,"L":1,"XL":0}', ARRAY['img/barcelona_25-26_home_fan_1.webp','img/barcelona_25-26_home_fan_2.webp','img/barcelona_25-26_home_fan_3.webp','img/barcelona_25-26_home_fan_4.webp','img/barcelona_25-26_home_fan_5.webp','img/barcelona_25-26_home_fan_6.webp','img/barcelona_25-26_home_fan_7.webp','img/barcelona_25-26_home_fan_8.webp']),
(6, 'Temporada 25/26', 'Camiseta visitante Barcelona 25/26', 'Camiseta visitante del FC Barcelona 2025-26 en elegante colorway blanco con detalles dorados y blaugrana. La segunda equipación más exclusiva del Barça. Versión Fan de alta calidad.', 99000, 10.44, '{"S":0,"M":2,"L":1,"XL":0}', ARRAY['img/barclona_25-26_away_white_1.webp','img/barclona_25-26_away_white_2.webp','img/barclona_25-26_away_white_3.webp','img/barclona_25-26_away_white_4.webp','img/barclona_25-26_away_white_5.webp','img/barclona_25-26_away_white_6.webp','img/barclona_25-26_away_white_7.webp']),
(7, 'Temporada 25/26', 'Camiseta local Bayern Múnich 25/26', 'La camiseta local del Bayern München temporada 2025-26 en el característico rojo bávaro con detalles en blanco. Diseño limpio y poderoso del gigante alemán. Versión Fan premium de los campeones de la Bundesliga.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":1}', ARRAY['img/bayern_munich_25-26_home_fan_1.webp','img/bayern_munich_25-26_home_fan_2.webp','img/bayern_munich_25-26_home_fan_3.webp','img/bayern_munich_25-26_home_fan_4.webp','img/bayern_munich_25-26_home_fan_5.webp','img/bayern_munich_25-26_home_fan_6.webp','img/bayern_munich_25-26_home_fan_7.webp','img/bayern_munich_25-26_home_fan_8.webp']),
(8, 'Temporada 25/26', 'Camiseta tercera Bayern Múnich 25/26', 'Tercera equipación del Bayern München 2025-26 en negro elegante. Un diseño audaz y moderno que rompe con el clásico rojo bávaro. Edición limitada Versión Fan para los seguidores más atrevidos del gigante alemán.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":1}', ARRAY['img/bayern_munich_25-26_tercera_negra_fan_1.webp','img/bayern_munich_25-26_tercera_negra_fan_2.webp','img/bayern_munich_25-26_tercera_negra_fan_3.webp','img/bayern_munich_25-26_tercera_negra_fan_4.webp','img/bayern_munich_25-26_tercera_negra_fan_5.webp','img/bayern_munich_25-26_tercera_negra_fan_6.webp']),
(9, 'Colección 2026', 'Camiseta local Brasil 26', 'La canarinha para el Mundial 2026. El icónico amarillo de Vinicius Jr. y Rodrygo con detalles verdes y el escudo de la CBF bordado. Para los hinchas de la Seleção que sueñan con el hexacampeonato.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/brasil_2026_version_fan_1.webp','img/brasil_2026_version_fan_2.webp','img/brasil_2026_version_fan_3.webp','img/brasil_2026_version_fan_4.webp','img/brasil_2026_version_fan_5.webp','img/brasil_2026_version_fan_6.webp','img/brasil_2026_version_fan_7.webp']),
(10, 'Colección 2026', 'Camiseta local Colombia 26', 'La tricolor en su versión mundialista 2026. El amarillo dorado de James, Díaz y Córdoba con los detalles azules y rojos que identifican a Los Cafeteros. Para los que creen en el sueño de la primera estrella.', 99000, 10.44, '{"S":0,"M":4,"L":4,"XL":0}', ARRAY['img/colombia_2026_1.webp','img/colombia_2026_2.webp','img/colombia_2026_3.webp','img/colombia_2026_4.webp','img/colombia_2026_5.webp','img/colombia_2026_6.webp']),
(11, 'Temporada 25/26', 'Camiseta local Liverpool 25/26', 'El rojo de Anfield para la temporada 2025-26. La camiseta local del Liverpool con el escudo del Liverbird y el espíritu de You''ll Never Walk Alone. Versión Fan del equipo de Arne Slot.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/liverpool_25-26_home_red_fan_1.webp','img/liverpool_25-26_home_red_fan_2.webp','img/liverpool_25-26_home_red_fan_3.webp','img/liverpool_25-26_home_red_fan_4.webp','img/liverpool_25-26_home_red_fan_5.webp','img/liverpool_25-26_home_red_fan_6.webp','img/liverpool_25-26_home_red_fan_7.webp','img/liverpool_25-26_home_red_fan_8.webp']),
(12, 'Temporada 25/26', 'Camiseta visitante Liverpool 25/26', 'Camiseta visitante del Liverpool 2025-26 en blanco con detalles en rojo y dorado. El toque elegante del equipo de Anfield para los partidos fuera de casa. Versión Fan de alta calidad.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/liverpool_25-26_white_fan_1.webp','img/liverpool_25-26_white_fan_2.webp','img/liverpool_25-26_white_fan_3.webp','img/liverpool_25-26_white_fan_4.webp','img/liverpool_25-26_white_fan_5.webp','img/liverpool_25-26_white_fan_6.webp','img/liverpool_25-26_white_fan_7.webp','img/liverpool_25-26_white_fan_8.webp','img/liverpool_25-26_white_fan_9.webp']),
(13, 'Temporada 25/26', 'Camiseta tercera Manchester City 25/26', 'Tercera equipación del Manchester City 2025-26 en negro. Un diseño oscuro y sofisticado del campeón inglés, alejado del clásico celeste. Versión Fan de edición limitada para los Citizens más atrevidos.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/man_city_25-26_black_fan_1.webp','img/man_city_25-26_black_fan_2.webp','img/man_city_25-26_black_fan_3.webp','img/man_city_25-26_black_fan_4.webp','img/man_city_25-26_black_fan_5.webp','img/man_city_25-26_black_fan_6.webp','img/man_city_25-26_black_fan_7.webp','img/man_city_25-26_black_fan_8.webp']),
(14, 'Temporada 25/26', 'Camiseta local Manchester City 25/26', 'La camiseta local del Manchester City 2025-26 en el clásico celeste de los Citizens. El diseño del campeón inglés para la nueva era. Versión Fan premium con tela ligera y acabados de calidad.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/man_city_25-26_fan_home_1.webp','img/man_city_25-26_fan_home_2.webp','img/man_city_25-26_fan_home_3.webp','img/man_city_25-26_fan_home_4.webp','img/man_city_25-26_fan_home_5.webp','img/man_city_25-26_fan_home_6.webp']),
(15, 'Leyendas Clásicas', 'Camiseta local Retro Manchester United 1998', 'Camiseta retro del Manchester United temporada 1997-98, año del histórico doblete de Ferguson. El clásico rojo de Old Trafford con el escudo vintage y el diseño Sharp Electronics. Una joya para coleccionistas del fútbol inglés.', 120000, 18.44, '{"S":0,"M":1,"L":0,"XL":0}', ARRAY['img/man_ud_retro_98_home_1.webp','img/man_ud_retro_98_home_2.webp','img/man_ud_retro_98_home_3.webp','img/man_ud_retro_98_home_4.webp','img/man_ud_retro_98_home_5.webp','img/man_ud_retro_98_home_6.webp','img/man_ud_retro_98_home_7.webp','img/man_ud_retro_98_home_8.webp']),
(16, 'Temporada 25/26', 'Camiseta local Manchester United 25/26', 'La camiseta local del Manchester United temporada 2025-26 en rojo intenso con detalles en blanco y negro. El renacimiento de los Red Devils de Old Trafford bajo la nueva era. Versión Fan de alta calidad.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/manchester_united_25-26_home_fan_1.webp','img/manchester_united_25-26_home_fan_2.webp','img/manchester_united_25-26_home_fan_3.webp','img/manchester_united_25-26_home_fan_4.webp','img/manchester_united_25-26_home_fan_5.webp','img/manchester_united_25-26_home_fan_6.webp','img/manchester_united_25-26_home_fan_7.webp','img/manchester_united_25-26_home_fan_8.webp','img/manchester_united_25-26_home_fan_9.webp']),
(17, 'Colección 2026', 'Camiseta Edición Especial Portugal 26', 'Edición especial de la Selección de Portugal para el ciclo 2026-27. El rojo de Cristiano Ronaldo y Bruno Fernandes en un diseño único y atrevido que rompe con lo convencional. Versión Fan de colección exclusiva.', 110000, 13.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/portugal_2026_especial_26-27_fan_1.webp','img/portugal_2026_especial_26-27_fan_2.webp','img/portugal_2026_especial_26-27_fan_3.webp','img/portugal_2026_especial_26-27_fan_4.webp','img/portugal_2026_especial_26-27_fan_5.webp']),
(18, 'Temporada 25/26', 'Camiseta local PSG 25/26', 'La camiseta local del Paris Saint-Germain temporada 2025-26 con los colores azul, rojo y blanco de la capital francesa. Elegancia parisina en cada detalle. Versión Fan del club más glamuroso de la Ligue 1.', 99000, 10.44, '{"S":0,"M":1,"L":1,"XL":0}', ARRAY['img/psg_25-26_home_fan_1.webp','img/psg_25-26_home_fan_2.webp','img/psg_25-26_home_fan_3.webp','img/psg_25-26_home_fan_4.webp','img/psg_25-26_home_fan_5.webp','img/psg_25-26_home_fan_6.webp','img/psg_25-26_home_fan_7.webp','img/psg_25-26_home_fan_8.webp']),
(19, 'Temporada 25/26', 'Camiseta visitante Real Madrid 25/26', 'Camiseta visitante del Real Madrid 2025-26 en azul marino. El equipo más ganador de la historia con una segunda equipación de elegancia y poder. Versión Fan para los madridistas que dominan también de visitante.', 99000, 10.44, '{"S":0,"M":2,"L":1,"XL":0}', ARRAY['img/real_madrid_25-26_azul_fan_1.webp','img/real_madrid_25-26_azul_fan_2.webp','img/real_madrid_25-26_azul_fan_3.webp','img/real_madrid_25-26_azul_fan_4.webp','img/real_madrid_25-26_azul_fan_5.webp']),
(20, 'Leyendas Clásicas', 'Camiseta local Retro Real Madrid 1999/00', 'Camiseta retro del Real Madrid temporada 1999-2000, la era de los Galácticos. El blanco mítico de Figo, Raúl, Morientes y Hierro con el escudo vintage dorado. Una pieza de colección para quienes vivieron la gloria.', 120000, 15.44, '{"S":0,"M":1,"L":0,"XL":0}', ARRAY['img/real_majdrid_retro_1999-00_home_fan_1.webp','img/real_majdrid_retro_1999-00_home_fan_2.webp','img/real_majdrid_retro_1999-00_home_fan_3.webp','img/real_majdrid_retro_1999-00_home_fan_4.webp','img/real_majdrid_retro_1999-00_home_fan_5.webp','img/real_majdrid_retro_1999-00_home_fan_6.webp','img/real_majdrid_retro_1999-00_home_fan_7.webp','img/real_majdrid_retro_1999-00_home_fan_8.webp']),
(24, 'Women''s Collection', 'Camiseta local Colombia 26 (Mujer)', 'Camiseta de la Selección Colombia 2026 en corte femenino. Diseño ajustado con el icónico amarillo tricolor y silueta moderna. Para las hinchas que visten la pasión con estilo propio. Disponible en todas las tallas.', 99000, 10.44, '{"S":2,"M":2,"L":0,"XL":0}', ARRAY['img/colombia_2026_mujer_fan_1.webp','img/colombia_2026_mujer_fan_2.webp','img/colombia_2026_mujer_fan_3.webp','img/colombia_2026_mujer_fan_4.webp','img/colombia_2026_mujer_fan_5.webp']),
(25, 'Temporada 25/26', 'Camiseta local Real Madrid 25/26', 'La camiseta local del Real Madrid 2026 en el eterno blanco merengue. Diseño moderno que honra la tradición del club más laureado del mundo. Versión Fan premium del campeón de Champions. Disponible en todas las tallas.', 99000, 10.44, '{"S":0,"M":2,"L":1,"XL":0}', ARRAY['img/real_madrid_home_white_fan_2026_1.webp','img/real_madrid_home_white_fan_2026_2.webp','img/real_madrid_home_white_fan_2026_3.webp','img/real_madrid_home_white_fan_2026_4.webp','img/real_madrid_home_white_fan_2026_5.webp','img/real_madrid_home_white_fan_2026_6.webp','img/real_madrid_home_white_fan_2026_7.webp']),
